"use client";

import { useState, useEffect, useRef } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";

type Product = { id: number; name: string; price: number; category: string; unit: string };
type CartItem = { product: Product; quantity: number };

export default function CartPage() {
  const router = useRouter();
  const [cart, setCart] = useState<CartItem[]>([]);
  const [name, setName] = useState("");
  const [flatNo, setFlatNo] = useState("");
  const [phone, setPhone] = useState("");
  const [paymentMethod, setPaymentMethod] = useState<"cod" | "tab">("cod");
  const [placing, setPlacing] = useState(false);
  const [orderPlaced, setOrderPlaced] = useState<{ id: number; total: number } | null>(null);
  const cartLoaded = useRef(false);

  useEffect(() => {
    const saved = localStorage.getItem("lucky_cart");
    if (saved) { try { setCart(JSON.parse(saved)); } catch { /* */ } }
    cartLoaded.current = true;
    const u = localStorage.getItem("lucky_user");
    if (u) { try { const p = JSON.parse(u); setName(p.name || ""); setFlatNo(p.flat_no || ""); setPhone(p.phone || ""); } catch { /* */ } }
  }, []);

  useEffect(() => { if (cartLoaded.current) localStorage.setItem("lucky_cart", JSON.stringify(cart)); }, [cart]);

  const total = cart.reduce((s, i) => s + i.product.price * i.quantity, 0);

  function updateQty(id: number, delta: number) {
    setCart(prev => prev.map(i => i.product.id === id ? { ...i, quantity: i.quantity + delta } : i).filter(i => i.quantity > 0));
  }

  async function placeOrder() {
    if (!name.trim() || !flatNo.trim() || !phone.trim()) { alert("Please fill in your name, flat number, and phone number"); return; }
    if (cart.length === 0) return;
    setPlacing(true);
    try {
      const userRes = await fetch("/api/users", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ name, flat_no: flatNo, phone }) });
      const user = await userRes.json();
      localStorage.setItem("lucky_user", JSON.stringify(user));
      const orderRes = await fetch("/api/orders", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ user_id: user.id, payment_method: paymentMethod, items: cart.map(i => ({ product_id: i.product.id, quantity: i.quantity })) }) });
      const order = await orderRes.json();
      setOrderPlaced(order); setCart([]); localStorage.removeItem("lucky_cart");
    } catch { alert("Failed to place order. Please try again."); }
    finally { setPlacing(false); }
  }

  if (orderPlaced) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="card p-8 mx-4 text-center max-w-sm w-full animate-in">
          <div className="text-5xl mb-4">&#10003;</div>
          <h2 className="text-2xl font-bold text-accent mb-2">Order Placed!</h2>
          <p className="text-gray-500 mb-1">Order #{orderPlaced.id}</p>
          <p className="text-2xl font-bold text-gray-800 mb-2">&#8377;{orderPlaced.total}</p>
          <p className="text-sm text-gray-400 mb-6">{paymentMethod === "cod" ? "Pay when delivered" : "Added to your monthly tab"}</p>
          <p className="text-sm text-gray-500 mb-6">Lucky Store will check availability and confirm shortly.</p>
          <Link href="/" className="btn btn-primary px-6 py-3 rounded-xl text-base">Back to Store</Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen">
      <header className="header">
        <div className="max-w-lg mx-auto px-4 py-3 flex items-center gap-4">
          <button onClick={() => router.back()} className="text-xl">&larr;</button>
          <h1 className="text-xl font-bold">Your Cart</h1>
        </div>
      </header>

      <main className="max-w-lg mx-auto px-4 py-4 pb-32">
        {cart.length === 0 ? (
          <div className="text-center py-16 animate-in">
            <div className="text-5xl mb-4">&#x1F6D2;</div>
            <p className="text-gray-400 text-lg">Your cart is empty</p>
            <Link href="/" className="inline-block mt-4 text-accent font-semibold">Browse products</Link>
          </div>
        ) : (
          <div className="space-y-4 animate-in">
            <div className="card divide-y divide-gray-100">
              {cart.map(item => (
                <div key={item.product.id} className="flex items-center justify-between p-4">
                  <div className="flex-1">
                    <h3 className="text-sm font-medium text-gray-800">{item.product.name}</h3>
                    <p className="text-price font-semibold text-sm mt-1">&#8377;{item.product.price} / {item.product.unit}</p>
                  </div>
                  <div className="flex items-center gap-2">
                    <div className="qty-stepper h-8">
                      <button onClick={() => updateQty(item.product.id, -1)}>-</button>
                      <span className="px-2 text-sm">{item.quantity}</span>
                      <button onClick={() => updateQty(item.product.id, 1)}>+</button>
                    </div>
                    <span className="text-sm font-bold text-gray-700 w-16 text-right">&#8377;{item.product.price * item.quantity}</span>
                  </div>
                </div>
              ))}
            </div>

            <div className="card p-4">
              <div className="flex justify-between text-lg font-bold">
                <span>Total</span>
                <span className="text-price">&#8377;{total}</span>
              </div>
            </div>

            <div className="card p-4">
              <h3 className="font-bold text-gray-800 mb-3">Delivery Details</h3>
              <div className="space-y-3">
                <input type="text" placeholder="Your Name" value={name} onChange={e => setName(e.target.value)} className="input" />
                <input type="text" placeholder="Flat No. (e.g. A-101)" value={flatNo} onChange={e => setFlatNo(e.target.value)} className="input" />
                <input type="tel" placeholder="Phone Number" value={phone} onChange={e => setPhone(e.target.value)} className="input" />
              </div>
            </div>

            <div className="card p-4">
              <h3 className="font-bold text-gray-800 mb-3">Payment Method</h3>
              <div className="space-y-2">
                {(["cod", "tab"] as const).map(m => (
                  <label key={m} className={`flex items-center gap-3 p-3 rounded-lg border cursor-pointer transition-colors ${
                    paymentMethod === m ? "border-[var(--c-cyan)] bg-[#eef1ff]" : "border-gray-200"
                  }`}>
                    <input type="radio" name="payment" checked={paymentMethod === m} onChange={() => setPaymentMethod(m)} className="accent-[var(--c-emerald)]" />
                    <div>
                      <div className="font-medium text-sm">{m === "cod" ? "Cash on Delivery" : "Add to Monthly Tab"}</div>
                      <div className="text-xs text-gray-400">{m === "cod" ? "Pay when you receive" : "Pay at end of month"}</div>
                    </div>
                  </label>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>

      {cart.length > 0 && (
        <div className="fixed bottom-0 left-0 right-0 z-50 animate-slide-up">
          <div className="frosted">
            <div className="max-w-lg mx-auto px-4 py-4">
              <button onClick={placeOrder} disabled={placing} className="btn btn-primary w-full py-4 rounded-xl text-lg disabled:opacity-50">
                {placing ? "Placing Order..." : `Place Order - \u20B9${total}`}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
